(window.webpackJsonp=window.webpackJsonp||[]).push([[196],{823:function(n,r){n.exports='\x3c!-- \r\ntitle: Ranger\r\nsort: \r\n--\x3e \r\n\r\n> 效率非常高的终端文件管理器\r\n\r\n## 基本操作\r\n\r\n### 快捷键\r\n\r\n| 按键         | 功能                           |\r\n| ------------ | ------------------------------ |\r\n| ?m/k/c/s     | 查看帮助/菜单/快捷键/命令/设置 |\r\n| g            | 跳转                           |\r\n| d            | 剪贴                           |\r\n| p            | 粘贴                           |\r\n| SPACE/v/V/uv | 选择/反选/视觉模式/取消选择    |\r\n| r            | 打开方式                       |\r\n| c            | 修改                           |\r\n| y            | 复制                           |\r\n| +/-/=        | 赋权限                         |\r\n| / nN         | 搜索/下一个                    |\r\n| o            | 排序                           |\r\n| M            | 模式                           |\r\n| g            | 标签页                         |\r\n| S            | shell打开当前目录              |\r\n\r\n### 操作\r\n\r\n| 快捷键  | 功能               |\r\n| ------- | ------------------ |\r\n| z-h     | 显示/隐藏文件      |\r\n| c-w     | 修改文件名         |\r\n| y-y     | 复制文件           |\r\n| p-p o   | 粘贴/覆盖文件      |\r\n| d-d D u | 剪贴/删除/查看大小 |\r\n| o-s     | 文件大小排序       |\r\n\r\n## 问题\r\n\r\n- 挂载u盘\r\n\r\n  ```bash\r\n  yay install usbmount\r\n  vim /etc/usbmount/usbmount.conf\r\n  # 对挂载的U盘拥有写权限\r\n  MOUNTOPTIOS="rw,user,noatime,nodiratime\r\n  ```\r\n\r\n  '}}]);